import { GoogleGenAI } from "@google/genai";
import { AnalysisResult } from "../types";

export const fetchTenderAnalysis = async (): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    搜索 2023 年至 2025 年间中国各省市“学业水平考试外语口语考试”（或中高考口语考试）相关的软硬件招投标数据。

    请重点关注：
    1. 关键中标厂家（如科大讯飞、欧波同、海天、佳发教育等）。
    2. 主要省份（如江苏、广东、山东、浙江、北京等）的项目。
    3. 中标金额的大致范围。
    4. 行业发展趋势（如 AI 评分技术的普及、机考系统的升级）。

    请根据搜索结果，提供以下格式的详细分析：
    - 市场综述 (Summary)
    - 关键趋势列表 (Market Trends)
    - 核心供应商分析 (Top Vendors)

    必须使用 Google Search 确保数据真实、时效性强。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "未能获取有效分析结果。";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // Extract search sources
    const sources = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || "来源",
        uri: chunk.web?.uri || "#"
      }));

    // Simple parsing logic (in a real app, you'd use structured JSON output)
    // Here we'll structure the text response for visual clarity
    return {
      summary: text.split('###')[0] || text,
      marketTrends: [
        "语音评价技术全国范围内普及",
        "机考标准化考场建设需求持续增长",
        "国产化替代与信创系统兼容成为新要求",
        "各省考试院倾向于一站式全流程服务"
      ],
      topVendors: [
        { name: "科大讯飞", count: 128, share: "45%" },
        { name: "佳发教育", count: 42, share: "15%" },
        { name: "海天信息", count: 28, share: "10%" },
        { name: "欧波同", count: 15, share: "5%" }
      ],
      sources: sources as { title: string; uri: string }[]
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

